START TRANSACTION;

SET FOREIGN_KEY_CHECKS = 0;

DROP TABLE IF EXISTS Timesheet;
DROP TABLE IF EXISTS Employee_Project;
DROP TABLE IF EXISTS Invoice;
DROP TABLE IF EXISTS Project;
DROP TABLE IF EXISTS Employee;
DROP TABLE IF EXISTS Client;
DROP TABLE IF EXISTS Department;

SET FOREIGN_KEY_CHECKS = 1;

CREATE TABLE Department (
  department_id INT PRIMARY KEY,
  name VARCHAR(100) NOT NULL,
  manager_employee_id INT NULL
);

CREATE TABLE Employee (
  employee_id INT PRIMARY KEY,
  first_name VARCHAR(50) NOT NULL,
  last_name VARCHAR(50) NOT NULL,
  email VARCHAR(150) NOT NULL UNIQUE,
  hire_date DATE NOT NULL,
  job_title VARCHAR(100) NOT NULL,
  salary DECIMAL(12,2) NOT NULL,
  department_id INT NOT NULL,
  CONSTRAINT fk_employee_department
    FOREIGN KEY (department_id) REFERENCES Department(department_id)
);

ALTER TABLE Department
  ADD CONSTRAINT fk_department_manager
  FOREIGN KEY (manager_employee_id)
  REFERENCES Employee(employee_id);

CREATE TABLE Client (
  client_id INT PRIMARY KEY,
  name VARCHAR(150) NOT NULL,
  industry VARCHAR(100) NOT NULL,
  contact_name VARCHAR(100) NOT NULL,
  contact_email VARCHAR(150) NOT NULL,
  contact_phone VARCHAR(30) NOT NULL
);

CREATE TABLE Project (
  project_id INT PRIMARY KEY,
  client_id INT NOT NULL,
  name VARCHAR(150) NOT NULL,
  description TEXT NOT NULL,
  start_date DATE NOT NULL,
  end_date DATE NULL,
  status VARCHAR(30) NOT NULL DEFAULT 'planned',
  budget DECIMAL(12,2) NOT NULL,
  CONSTRAINT fk_project_client
    FOREIGN KEY (client_id) REFERENCES Client(client_id),
  CONSTRAINT check_date_validity CHECK (start_date <= end_date)
);

CREATE TABLE Employee_Project (
  employee_id INT NOT NULL,
  project_id INT NOT NULL,
  assignment_start_date DATE NOT NULL,
  role_on_project VARCHAR(100) NOT NULL,
  allocation_percent DECIMAL(5,2) NOT NULL,
  assignment_end_date DATE NULL,
  PRIMARY KEY (employee_id, project_id, assignment_start_date),
  CONSTRAINT fk_employee_project_employee
    FOREIGN KEY (employee_id) REFERENCES Employee(employee_id),
  CONSTRAINT fk_employee_project_project
    FOREIGN KEY (project_id) REFERENCES Project(project_id)
);

CREATE TABLE Timesheet (
  timesheet_id INT PRIMARY KEY,
  employee_id INT NOT NULL,
  project_id INT NOT NULL,
  work_date DATE NOT NULL,
  hours DECIMAL(4,2) NOT NULL,
  billable_flag TINYINT(1) NOT NULL,
  notes TEXT NULL,
  CONSTRAINT fk_timesheet_employee
    FOREIGN KEY (employee_id) REFERENCES Employee(employee_id),
  CONSTRAINT fk_timesheet_project
    FOREIGN KEY (project_id) REFERENCES Project(project_id)
);

CREATE TABLE Invoice (
  invoice_id INT PRIMARY KEY,
  project_id INT NOT NULL,
  invoice_date DATE NOT NULL,
  amount DECIMAL(12,2) NOT NULL,
  status VARCHAR(30) NOT NULL DEFAULT 'draft',
  notes TEXT NULL,
  CONSTRAINT fk_invoice_project
    FOREIGN KEY (project_id) REFERENCES Project(project_id)
);

CREATE INDEX idx_project_status_end_date
  ON Project (status, end_date);

CREATE INDEX idx_invoice_project_invoice_date
  ON Invoice (project_id, invoice_date);

CREATE INDEX idx_timesheet_employee_work_date
  ON Timesheet (employee_id, work_date);

CREATE INDEX idx_timesheet_project_work_date_billable
  ON Timesheet (project_id, work_date, billable_flag);

CREATE INDEX idx_employee_project_project_dates
  ON Employee_Project (project_id, assignment_start_date, assignment_end_date);

